import{_ as e,o as r,c as l,a2 as t}from"./chunks/framework.ZhLefgN8.js";const f=JSON.parse('{"title":"实物股票","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/stock-transfer/physical-shares.md","filePath":"zh-CN/stock-trading/stock-transfer/physical-shares.md"}'),i={name:"stock-trading/stock-transfer/physical-shares.md"};function o(s,a,h,n,c,d){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="实物股票" tabindex="-1">实物股票 <a class="header-anchor" href="#实物股票" aria-label="Permalink to &quot;实物股票&quot;">​</a></h1><p>实物股票是以实体印刷的股票证书形式存在的股票，每份证书代表一定数量的股份，印有公司名称、股份数量、证书编号及股东姓名等信息。</p><p>目前长桥仅支持港股实物股票的存入和提取，账户类型为长桥综合（香港）账户。</p><hr><h2 id="存入实物股票" tabindex="-1">存入实物股票 <a class="header-anchor" href="#存入实物股票" aria-label="Permalink to &quot;存入实物股票&quot;">​</a></h2><h3 id="要求" tabindex="-1">要求 <a class="header-anchor" href="#要求" aria-label="Permalink to &quot;要求&quot;">​</a></h3><ul><li>实物股票持有人（Shareholder）与长桥证券账户持有人姓名必须相同</li><li>存入大额实物股票前，须提供近半年的相关股票交易记录（如结单）和实物股票的提货纸</li></ul><h3 id="处理时间" tabindex="-1">处理时间 <a class="header-anchor" href="#处理时间" aria-label="Permalink to &quot;处理时间&quot;">​</a></h3><p>自长桥收到实物股票起预计 12 个工作日内完成转入，实际时间以中央结算系统处理时间为准。</p><h3 id="费用" tabindex="-1">费用 <a class="header-anchor" href="#费用" aria-label="Permalink to &quot;费用&quot;">​</a></h3><p>同日存入 1-10 张：只代收政府印花税 5 港币 / 张<br> 同日存入 11 张及以上：代收政府印花税 + 加收手续费 5 港币 / 张<br> 如使用转让书，印花税只收取一次。如存入不成功，已收取的印花税不作退还。</p><h3 id="存入流程" tabindex="-1">存入流程 <a class="header-anchor" href="#存入流程" aria-label="Permalink to &quot;存入流程&quot;">​</a></h3><p><strong>第一步：线上提交实物股票资料</strong></p><ol><li>拍摄实物股票正面照片（每一只股票均需拍照）</li><li>上传图片至长桥客服或客户经理，说明需存入实物股票</li><li>长桥核实股票可存入后，2 个工作日内反馈结果</li></ol><p><strong>第二步：前往香港办公室递交文件</strong></p><ol><li>文件签署：在股票正本背面「转让人签名」处签名。如使用转让书，在背面转让人签名处签名（签名须与股票过户处的签名留存一致，最多可同时签三个样式）</li><li>公司账户需盖公司印章和签名，如无印章则需填写「FOR AND ON BEHALF OF [股东名称]」并签名</li><li>本人亲自将签完名的实物股票、转让书（如有）交至长桥办公室（不接受邮寄）</li></ol><p>办公地址：中环港景街 1 号国际金融中心一期 18 楼 1801-1804, 1815-1816 室</p><p><a href="https://pub.lbkrs.com/files/202602/m8cRpKkmgvtKW7uh/_20260216.pdf" target="_blank" rel="noreferrer">实物股票存入表格</a></p><p>注意：必须同时完成线上提交和线下递交两个步骤，长桥方可执行存入指示。</p><hr><h2 id="提取实物股票" tabindex="-1">提取实物股票 <a class="header-anchor" href="#提取实物股票" aria-label="Permalink to &quot;提取实物股票&quot;">​</a></h2><h3 id="提取流程" tabindex="-1">提取流程 <a class="header-anchor" href="#提取流程" aria-label="Permalink to &quot;提取流程&quot;">​</a></h3><ol><li>联系客服获取实物股票提取表格，填写后提交</li><li>在账户内预留资金，用于后续费用扣款</li><li>长桥结算部门冻结相关股票和预计费用，在 CCASS 终端操作提货指令</li><li>股票从中央结算取得后，长桥会通知客户在 10 个工作日内取回股票</li><li>取回当天需携带身份证明文件核对身份，并在提货文件内签署确认</li></ol><p><a href="https://pub.lbkrs.com/files/202602/6kTEfaCUxAWB7v5R/20260216.pdf" target="_blank" rel="noreferrer">实物股票提取表格</a></p>',24)])])}const u=e(i,[["render",o]]);export{f as __pageData,u as default};
